const webhook = $('Main Webhook').first().json.body;
const historyItems = $('Fetch History').first().json.items || [];
const myId = $('Set Keys').first().json['My Provider ID'];
const sender = webhook.sender || {};
const eventType = webhook.event || 'message_received';

// Build chronological history with messageId + simple reaction array
// For reactions, the actual prospect is in reaction_sender; for messages, it's in sender
const prospectInfoEarly = (eventType === 'message_reaction')
  ? (webhook.reaction_sender || {})
  : sender;

const history = historyItems.slice().reverse().map(m => ({
  isMe: m.sender_id === myId || m.is_sender === 1,
  from: (m.sender_id === myId || m.is_sender === 1) ? 'Me' : (prospectInfoEarly.attendee_name || 'Prospect'),
  text: m.text || '',
  messageId: m.id || ''
}));

// Conversation URN
const chatProviderId = historyItems.length > 0 ? historyItems[0].chat_provider_id : '';
const conversationUrn = 'urn:li:msg_conversation:(urn:li:fsd_profile:' + myId + ',' + chatProviderId + ')';

// Profile URL — use prospectInfo so reactions fetch prospect's profile
const profileUrl = prospectInfoEarly.attendee_profile_url ||
  ('https://www.linkedin.com/in/' + (prospectInfoEarly.attendee_provider_id || ''));

// Branch on event type
if (eventType === 'message_reaction') {
  // The webhook for a reaction event has slightly different structure.
  // Try multiple field names for compatibility.
  const reactedMsgId = webhook.message_id || '';
  const reactionEmoji = (typeof webhook.reaction === 'string' ? webhook.reaction : (webhook.reaction || {}).value) || '?';
  const reactionSender = webhook.reaction_sender || {};
  const reactionSenderId = reactionSender.attendee_provider_id || '';

  // Filter 1 : reaction sender must NOT be Me
  if (reactionSenderId === myId) {
    return [];
  }

  // Filter 2 : reaction must be on my MOST RECENT message
  // Find my most recent message in history
  const maxMsgs = historyItems.filter(m => m.sender_id === myId || m.is_sender === 1);
  const maxLatest = maxMsgs[0]; // historyItems is newest-first, so maxMsgs[0] is my most recent
  if (!maxLatest || maxLatest.id !== reactedMsgId) {
    return [];
  }

  // Filter 3 : there must be at least one prospect message in history (else it's just icebreaker)
  const prospectMsgs = historyItems.filter(m => m.sender_id !== myId && m.is_sender !== 1);
  if (prospectMsgs.length === 0) {
    return [];
  }

  // OK, this is a valid reaction event we should respond to.
  // Synthesize a virtual lastMessage for the agents.
  const virtualMsg = '[Réaction du prospect : ' + reactionEmoji + ' (le prospect a réagi à ton dernier message avec cet emoji, sans répondre par texte)]';

  return [{
    json: {
      conversationUrn,
      chatId: webhook.chat_id || '',
      lastMessage: virtualMsg,
      prospect: prospectInfoEarly.attendee_name || '',
      profileUrl,
      senderProviderId: prospectInfoEarly.attendee_provider_id || '',
      history,
      details: null,
      hasAudio: false,
      audioItems: [],
      audioMessageId: '',
      audioAttachmentId: '',
      audioMimetype: '',
      originalText: virtualMsg,
      isReaction: true,
      reactionEmoji: reactionEmoji
    }
  }];
}

// Default branch : message_received (text or audio, current behavior)
let hasAudio = false;
let audioMessageId = '';
let audioAttachmentId = '';
let audioMimetype = '';
let originalText = webhook.message || '';

// Detect ALL audio attachments since the last bot message
const audioItems = [];
for (let i = 0; i < historyItems.length; i++) {
  const m = historyItems[i];
  const fromMe = (m.sender_id === myId) || (m.is_sender === 1);
  if (fromMe) break;
  const attachments = m.attachments || [];
  const audio = attachments.find(a =>
    (a.mimetype && String(a.mimetype).toLowerCase().startsWith('audio')) ||
    (a.type && String(a.type).toLowerCase().includes('audio'))
  );
  if (audio) {
    audioItems.push({
      messageId: m.id || m.message_id || '',
      attachmentId: audio.id || '',
      mimetype: audio.mimetype || 'audio/mp4'
    });
  }
}

if (audioItems.length > 0) {
  hasAudio = true;
  audioMessageId = audioItems[0].messageId;
  audioAttachmentId = audioItems[0].attachmentId;
  audioMimetype = audioItems[0].mimetype;
}

return [{
  json: {
    conversationUrn,
    chatId: webhook.chat_id || '',
    lastMessage: originalText,
    prospect: sender.attendee_name || '',
    profileUrl,
    senderProviderId: sender.attendee_provider_id || '',
    history,
    details: null,
    hasAudio,
    audioItems,
    audioMessageId,
    audioAttachmentId,
    audioMimetype,
    originalText,
    isReaction: false
  }
}];

// Get sender info
const sender = $('Main Webhook').first().json.body.sender || {};
const profileUrl = (sender.attendee_profile_url || '').toLowerCase();
const providerId = (sender.attendee_provider_id || '').toLowerCase();
const name = (sender.attendee_name || '').toLowerCase();

// Get public identifier from Resolve Profile node
const resolved = $('Resolve Profile').first().json;
const publicId = (resolved.public_identifier || '').toLowerCase();

// 1) TEST ALLOWLIST (if non-empty, ONLY these profiles can talk to the bot)
const allowRaw = $('Paused Profiles').first().json.test_allowlist || '';
const allowList = allowRaw.split(',').map(s => s.trim().toLowerCase()).filter(s => s.length > 0);

if (allowList.length > 0) {
  const isAllowed = allowList.some(id => {
    if (publicId && publicId === id) return true;
    if (profileUrl.includes(id)) return true;
    if (providerId === id) return true;
    if (name === id) return true;
    return false;
  });
  if (!isAllowed) {
    return [];
  }
}

// 2) Existing paused list (blacklist)
const pausedRaw = $('Paused Profiles').first().json.paused_profiles || '';
const pausedList = pausedRaw.split(',').map(s => s.trim().toLowerCase()).filter(s => s.length > 0);

const isPaused = pausedList.some(id => {
  if (publicId && publicId === id) return true;
  if (profileUrl.includes(id)) return true;
  if (providerId === id) return true;
  if (name === id) return true;
  return false;
});

if (isPaused) {
  return [];
}

return $input.all();

// After the 40s wait, re-check the chat: if a newer message has arrived,
// abandon this run silently — the newer message's own webhook will produce
// the reply (with both messages now in its history context).
//
// For reaction events, this debounce is not needed (a reaction always points
// to a specific message_id in the past). We let it through and Normalize Raw
// handles the filtering (must be on my latest message, etc.).

const items = $('Fetch History').first().json.items || [];
const webhook = $('Main Webhook').first().json.body || {};
const myId = $('Set Keys').first().json['My Provider ID'];

// Bypass for reaction events — Normalize Raw does its own filtering
if (webhook.event === 'message_reaction') {
  return $input.all();
}

if (items.length === 0) return $input.all();

const latest = items[0];

// Defensive: if the latest message is somehow already from us
// (a parallel run already replied), bail.
if (latest.sender_id === myId || latest.is_sender === 1) {
  return [];
}

// Compare the message_id of the message that triggered THIS webhook
// against the id of the latest message in the chat. If they differ,
// a newer message has arrived during the 40s wait — exit silently.
const webhookMsgId = webhook.message_id || '';
const latestId = latest.id || '';

if (webhookMsgId && latestId && webhookMsgId !== latestId) {
  return [];
}

// Still the latest message — proceed with the reply pipeline.
return $input.all();

const raw = $('Normalize Raw').first().json;
const transcriptions = $input.all().map(i => i.json);

// Build messageId -> transcription map
const transcMap = {};
for (const t of transcriptions) {
  if (t.messageId && t.text) transcMap[t.messageId] = t.text;
}

// Patch history: replace empty text with '[Vocal] <transcription>'
const patchedHistory = raw.history.map(m => {
  if (m.messageId && transcMap[m.messageId]) {
    return { ...m, text: '[Vocal] ' + transcMap[m.messageId] };
  }
  return m;
});

// Compute lastMessage from the very latest history entry (chronologically last)
let lastMessage = raw.originalText || '';
const latest = patchedHistory[patchedHistory.length - 1];
if (latest && latest.messageId && transcMap[latest.messageId]) {
  const t = transcMap[latest.messageId];
  lastMessage = lastMessage
    ? (raw.originalText + '\n[Vocal transcrit] ' + t)
    : ('[Vocal transcrit] ' + t);
}

return [{
  json: {
    conversationUrn: raw.conversationUrn,
    chatId: raw.chatId,
    lastMessage,
    prospect: raw.prospect,
    profileUrl: raw.profileUrl,
    senderProviderId: raw.senderProviderId,
    history: patchedHistory,
    details: null
  }
}];

const r = $input.first().json;
if (r.handover === true) {
  return [{ json: { output: 'PAUSE_CONVERSATION', tools_called: r.tools_called || [], handover_reason: r.handover_reason || '' } }];
}
const messages = (r.messages || []).map(m => String(m).trim()).filter(Boolean);
const combined = messages.join(' && ');
return [{ json: { output: combined, tools_called: r.tools_called || [], cost_usd: r.cost_usd, duration_ms: r.duration_ms, num_turns: r.num_turns } }];
